import java.security.SecureRandom

object SessionManager {
    private const val SESSION_ID_LENGTH = 32
    private const val TOKEN_LENGTH = 32
    private const val ALPHANUMERIC_CHARS = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
    private val random = SecureRandom()

    fun generateSessionId(): String {
        return generateRandomString(SESSION_ID_LENGTH)
    }

    fun generateApiToken(): String {
        return generateRandomString(TOKEN_LENGTH)
