    private fun generateRandomString(length: Int): String {
        val sb = StringBuilder(length)
        for (i in 0 until length) {
            val index = random.nextInt(ALPHANUMERIC_CHARS.length)
            sb.append(ALPHANUMERIC_CHARS[index])
        }
        return sb.toString()
    }
}

